insert  into `conf_site`(`conf_id`,`conf_memo`,`conf_content`,`conf_active`) values (6,'입금안내','	- 입금자명과 통장 예금주가 일치하지 않을 경우 처리가 불가능 합니다.\n\n	- 계좌번호 및 예금자명 등을 변경하셔야 할 경우 고객센터로 문의 바랍니다.\n\n	- 은행 점검시간(23:30~00:30) 에는 신청을 피해 주시기 바랍니다.\n\n	- 1회 최대 입금 금액은 1천만원 이하로 부탁 드립니다.\n	\n	- 동일계좌로 재 입금 요청 시 5-10분의 간격을 두어야 합니다.\n		\n					\n					\n					\n					\n			',0);
insert  into `conf_site`(`conf_id`,`conf_memo`,`conf_content`,`conf_active`) values (7,'출금안내','	- 환전 신청 후 계좌 입금까지 3-5분 소요되며, 보유머니는 환전 신청 즉시 차감됩니다.\n\n	- 10분 이상 입금이 지연되는 경우, 계좌번호, 예금주의 변경 등은 고객센터에 문의해 주세요\n\n	- 은행 점검시간(23:30~00:30) 에는 신청을 피해 주시기 바랍니다.\n\n	- 최소 출금 신청 금액은 10,000원 입니다.		\n					\n					\n					\n					\n			',0);
